impl AddSettings {
    /// Resolve the [`AddSettings`] from the CLI and filesystem configuration.
    pub(crate) fn resolve(
        args: AddArgs,
        filesystem: Option<FilesystemOptions>,
        environment: EnvironmentOptions,
    ) -> Self {
        let AddArgs {
            packages,
            requirements,
            constraints,
            marker,
            dev,
            optional,
            group,
            editable,
            no_editable,
            no_editable_package,
            extra,
            raw,
            bounds,
            rev,
            tag,
            branch,
            lfs,
            no_sync,
            locked,
            frozen,
            active,
            no_active,
            installer,
            build,
            refresh,
            package,
            script,
            python,
            workspace,
            no_workspace,
            no_install_project,
            only_install_project,
            no_install_workspace,
            only_install_workspace,
            no_install_local,
            only_install_local,
            no_install_package,
            only_install_package,
        } = args;

        // Resolve flags from CLI and environment variables.
        let dev = dev || environment.dev.value == Some(true);
        let (editable, no_editable) = resolve_flag_pair(
            editable,
            no_editable,
            "editable",
            "no-editable",
            None,
            Some(environment.no_editable),
        );

        let dependency_type = if let Some(extra) = optional {
            DependencyType::Optional(extra)
        } else if let Some(group) = group {
            DependencyType::Group(group)
        } else if dev {
            DependencyType::Dev
        } else {
            DependencyType::Production
        };

        // Track the `--index` and `--default-index` arguments from the command-line.
        let indexes = installer
            .index_args
            .default_index
            .clone()
            .and_then(Maybe::into_option)
            .into_iter()
            .chain(
                installer
                    .index_args
                    .index
                    .clone()
                    .into_iter()
                    .flat_map(|v| v.clone())
                    .flatten()
                    .filter_map(Maybe::into_option),
            )
            .collect::<Vec<_>>();

        // Warn user if an ambiguous relative path was passed as a value for
        // `--index` or `--default-index`.
        for index in &indexes {
            index.url().warn_on_disambiguated_relative_path();
        }

        // If the user passed an `--index-url` or `--extra-index-url`, warn.
        if installer
            .index_args
            .index_url
            .as_ref()
            .is_some_and(Maybe::is_some)
        {
            if script.is_some() {
                warn_user_once!(
                    "Indexes specified via `--index-url` will not be persisted to the script; use `--default-index` instead."
                );
            } else {
                warn_user_once!(
                    "Indexes specified via `--index-url` will not be persisted to the `pyproject.toml` file; use `--default-index` instead."
                );
            }
        }

        if installer
            .index_args
            .extra_index_url
            .as_ref()
            .is_some_and(|extra_index_url| extra_index_url.iter().any(Maybe::is_some))
        {
            if script.is_some() {
                warn_user_once!(
                    "Indexes specified via `--extra-index-url` will not be persisted to the script; use `--index` instead."
                );
            } else {
                warn_user_once!(
                    "Indexes specified via `--extra-index-url` will not be persisted to the `pyproject.toml` file; use `--index` instead."
                );
            }
        }

        let filesystem_install_mirrors = filesystem
            .as_ref()
            .map(|fs| fs.install_mirrors.clone())
            .unwrap_or_default();

        let bounds = bounds.or(filesystem.as_ref().and_then(|fs| fs.add.add_bounds));
        let lfs = GitLfsSetting::new(lfs.then_some(true), environment.lfs);

        // Resolve flags from CLI and environment variables.
        let locked = resolve_flag(locked, "locked", environment.locked);
        let frozen = resolve_flag(frozen, "frozen", environment.frozen);
        let no_sync = resolve_flag(no_sync, "no-sync", environment.no_sync);

        // Check for conflicts between locked and frozen.
        check_conflicts(locked, frozen);

        // Check for conflicts between no_sync and frozen.
        check_conflicts(no_sync, frozen);

        let malware_settings = MalwareCheckSettings::from(&environment);

        Self {
            lock_check: resolve_lock_check(locked),
            frozen: resolve_frozen(frozen),
            active: flag(active, no_active, "active"),
            no_sync: no_sync.is_enabled(),
            packages,
            requirements,
            constraints: constraints
                .into_iter()
                .filter_map(Maybe::into_option)
                .collect(),
            marker,
            dependency_type,
            raw,
            bounds,
            rev,
            tag,
            branch,
            lfs,
            package,
            script,
            python: python.and_then(Maybe::into_option),
            workspace: flag(workspace, no_workspace, "workspace"),
            no_install_project,
            only_install_project,
            no_install_workspace,
            only_install_workspace,
            no_install_local,
            only_install_local,
            no_install_package,
            only_install_package,
            editable: EditableMode::from_args(
                flag(editable.into(), no_editable.into(), "editable"),
                no_editable_package,
            ),
            extras: extra.unwrap_or_default(),
            refresh: Refresh::from(refresh),
            indexes,
            settings: ResolverInstallerSettings::combine(
                resolver_installer_options(installer, build),
                filesystem,
                &environment,
            ),
            install_mirrors: environment
                .install_mirrors
                .combine(filesystem_install_mirrors),
            malware_settings,
        }
    }
}

